function doPost(e) {
  const lock = LockService.getScriptLock();
  lock.tryLock(10000);

  try {
    const doc = SpreadsheetApp.getActiveSpreadsheet();
    const sheet = doc.getActiveSheet();

    // Faz o parse dos dados enviados pelo React
    const data = JSON.parse(e.postData.contents);

    // Cria o timestamp
    const timestamp = new Date();

    // Tenta buscar as notas com ou sem acento, para garantir
    // O operador || "" garante que a célula fique vazia em vez de dar erro se não tiver a nota
    const redacao = data.redacao || data.redação || "";
    const matematica = data.matematica || data.matemática || "";
    const linguagens = data.linguagens || "";
    const humanas = data.humanas || data.cienciasHumanas || "";
    const natureza = data.natureza || data.cienciasNatureza || "";

    // Organiza a linha na ordem exata que você pediu
    const rowData = [
      timestamp,                    // Coluna A: Data/Hora
      data.cpf || "",               // Coluna B: CPF
      redacao,                      // Coluna C: Redação
      matematica,                   // Coluna D: Matemática
      linguagens,                   // Coluna E: Linguagens
      humanas,                      // Coluna F: Ciências Humanas
      natureza,                     // Coluna G: Ciências da Natureza
      data.nome || "",              // Coluna H: Nome (Opcional, mas útil ter)
      JSON.stringify(data)          // Coluna I: Backup Completo (Para segurança)
    ];

    // Adiciona a linha na planilha
    sheet.appendRow(rowData);

    // Retorna sucesso
    return ContentService.createTextOutput(JSON.stringify({ result: 'success' }))
      .setMimeType(ContentService.MimeType.JSON);

  } catch (e) {
    // Retorna erro se houver
    return ContentService.createTextOutput(JSON.stringify({ result: 'error', error: e.toString() }))
      .setMimeType(ContentService.MimeType.JSON);
  } finally {
    lock.releaseLock();
  }
}

