import React, { useState, useRef } from 'react';
import { analyzeReportCard, fileToGenerativePart } from './services/geminiService';
import { LoadingOverlay } from './components/LoadingOverlay';
import { ReviewScreen } from './components/ReviewScreen';
import { AppStep, ReportCardData } from './types';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>('form');
  const [cpf, setCpf] = useState('');
  const [file, setFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [analysisResult, setAnalysisResult] = useState<ReportCardData | null>(null);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleCpfChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    let value = e.target.value.replace(/\D/g, "");
    if (value.length > 11) value = value.slice(0, 11);

    value = value.replace(/(\d{3})(\d)/, "$1.$2");
    value = value.replace(/(\d{3})(\d)/, "$1.$2");
    value = value.replace(/(\d{3})(\d{1,2})$/, "$1-$2");

    setCpf(value);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const selectedFile = e.target.files[0];
      setFile(selectedFile);
      const url = URL.createObjectURL(selectedFile);
      setPreviewUrl(url);
      setErrorMsg(null);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (cpf.length < 14) {
      setErrorMsg("Por favor, preencha o CPF corretamente.");
      return;
    }
    if (!file) {
      setErrorMsg("Por favor, anexe o print do boletim.");
      return;
    }

    setStep('analyzing');
    setErrorMsg(null);

    try {
      const base64Data = await fileToGenerativePart(file);
      const result = await analyzeReportCard(base64Data, file.type);
      setAnalysisResult(result);
      setStep('review');
    } catch (error) {
      console.error(error);
      setErrorMsg("Ocorreu um erro ao analisar a imagem. Tente uma imagem mais clara.");
      setStep('form');
    }
  };

  const handleConfirm = () => {
    // Here you would typically send the data to your backend
    setStep('success');
  };

  const resetForm = () => {
    setStep('form');
    setCpf('');
    setFile(null);
    setPreviewUrl(null);
    setAnalysisResult(null);
    setErrorMsg(null);
    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
  };

  const retakePhoto = () => {
    setStep('form');
    // Keep CPF but clear file
    setFile(null);
    setPreviewUrl(null);
    setAnalysisResult(null);
    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center p-4 font-sans">
      <div className="w-full max-w-[480px] bg-white rounded-2xl shadow-2xl overflow-hidden relative">

        {/* Header */}
        <div className="bg-primary-red text-white p-8 border-b-[5px] border-dark-red text-center">
          <h1 className="font-black text-3xl uppercase leading-tight mb-2">Encceja 2025</h1>
          <p className="text-base font-normal opacity-90">Envie sua nota e concorra a prêmios!</p>
        </div>

        {/* Content */}
        <div className="bg-white min-h-[400px]">

          {step === 'form' && (
            <div className="p-8">
              <p className="text-gray-900 font-bold mb-6 text-lg text-center">
                Preencha seus dados para validar sua participação:
              </p>

              <form onSubmit={handleSubmit} className="space-y-6">
                <div>
                  <label htmlFor="cpf" className="block font-bold mb-2 text-gray-800 text-sm">SEU CPF:</label>
                  <input
                    type="text"
                    id="cpf"
                    placeholder="000.000.000-00"
                    maxLength={14}
                    value={cpf}
                    onChange={handleCpfChange}
                    className="w-full p-4 border-2 border-gray-200 rounded-lg text-lg font-sans transition-colors focus:border-primary-red focus:outline-none"
                    required
                  />
                </div>

                <div>
                  <label className="block font-bold mb-2 text-gray-800 text-sm">FOTO DO BOLETIM:</label>
                  <label htmlFor="file-input" className="block border-3 border-dashed border-primary-red bg-red-50 rounded-xl p-6 cursor-pointer hover:bg-red-100 hover:scale-[1.02] transition-all duration-300 text-center relative group">
                    <i className="fas fa-camera text-4xl text-primary-red mb-3 group-hover:scale-110 transition-transform"></i>
                    <div className="text-primary-red font-bold text-lg">ENVIAR PRINT DO BOLETIM</div>
                    <div className="text-gray-500 text-xs mt-2">Formatos aceitos: JPG, PNG (Print de tela)</div>
                  </label>
                  <input
                    ref={fileInputRef}
                    type="file"
                    id="file-input"
                    accept="image/*"
                    onChange={handleFileChange}
                    className="hidden"
                  />

                  {previewUrl && (
                    <div className="mt-4 text-center animate-fade-in">
                      <p className="mb-2 text-xs text-gray-500">Arquivo selecionado:</p>
                      <img 
                        src={previewUrl} 
                        alt="Preview" 
                        className="max-w-full max-h-48 object-contain mx-auto rounded-lg shadow-md border border-gray-200"
                      />
                    </div>
                  )}
                </div>

                {errorMsg && (
                  <div className="bg-red-100 border border-red-400 text-red-700 px-4 py-3 rounded relative text-sm text-center">
                    {errorMsg}
                  </div>
                )}

                <button 
                  type="submit" 
                  disabled={!cpf || !file}
                  className="w-full bg-primary-red text-white border-none py-4 text-lg font-black uppercase rounded-full cursor-pointer mt-4 shadow-lg hover:bg-dark-red hover:-translate-y-1 transition-all disabled:bg-gray-300 disabled:cursor-not-allowed disabled:shadow-none disabled:transform-none"
                >
                  Analisar e Concorrer
                </button>
              </form>
            </div>
          )}

          {step === 'analyzing' && (
            <LoadingOverlay />
          )}

          {step === 'review' && analysisResult && (
            <ReviewScreen 
              data={analysisResult} 
              onConfirm={handleConfirm}
              onRetake={retakePhoto}
            />
          )}

          {step === 'success' && (
            <div className="p-10 text-center animate-pop-in">
              <div className="mb-6">
                <i className="fas fa-check-circle text-green-500 text-6xl shadow-sm rounded-full"></i>
              </div>
              <h2 className="text-2xl font-black mb-4 text-gray-800">NOTA SALVA!</h2>
              <p className="text-lg leading-relaxed text-gray-600 mb-8">
                Seu boletim foi analisado e recebido com sucesso.
                <br /><br />
                Sua participação no <span className="text-primary-red font-black">SORTEIO DO TERMINE</span> já está confirmada!
              </p>

              <button 
                onClick={resetForm} 
                className="w-full bg-gray-800 hover:bg-black text-white font-bold py-4 rounded-full transition-colors uppercase tracking-wider shadow-lg"
              >
                Enviar Outro
              </button>
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="bg-gray-100 p-4 text-xs text-gray-500 text-center border-t border-gray-200">
          &copy; 2025 Termine Seus Estudos. Todos os direitos reservados.
        </div>

      </div>
    </div>
  );
};

export default App;

